<?php
require_once __DIR__.'/../includes/config.php'; require_customer(); $id=(int)($_GET['id']??0); $userId=(int)current_user()['id'];
$stmt=db()->prepare('SELECT * FROM orders WHERE id=? AND user_id=?'); $stmt->bind_param('ii',$id,$userId); $stmt->execute(); $order=$stmt->get_result()->fetch_assoc(); $stmt->close(); if(!$order){http_response_code(404);exit('Pesanan tidak ditemukan.');}
$itemsStmt=db()->prepare('SELECT * FROM order_items WHERE order_id=?'); $itemsStmt->bind_param('i',$id); $itemsStmt->execute(); $items=$itemsStmt->get_result(); $pageTitle='Detail Pesanan'; require __DIR__.'/../includes/header.php';
?>
<section class="section container"><div class="section-head"><div><span class="eyebrow">Detail Pesanan</span><h1><?= e($order['invoice_number']) ?></h1></div><span class="status status-<?= e($order['status']) ?>"><?= e(ucfirst($order['status'])) ?></span></div><div class="order-detail-grid"><div class="panel"><h3>Produk</h3><?php while($item=$items->fetch_assoc()): ?><div class="order-line"><div><strong><?= e($item['product_name']) ?></strong><small>Ukuran <?= e($item['size']) ?> · <?= (int)$item['quantity'] ?> item</small></div><strong><?= rupiah($item['subtotal']) ?></strong></div><?php endwhile; ?><hr><div class="summary-row total"><span>Total</span><strong><?= rupiah($order['total_amount']) ?></strong></div></div><div class="panel"><h3>Pengiriman</h3><p><strong><?= e($order['recipient_name']) ?></strong><br><?= e($order['phone']) ?></p><p><?= nl2br(e($order['shipping_address'])) ?></p><p><strong>Pembayaran:</strong> <?= e(strtoupper($order['payment_method'])) ?></p><?php if($order['notes']): ?><p><strong>Catatan:</strong> <?= e($order['notes']) ?></p><?php endif; ?></div></div></section>
<?php $itemsStmt->close(); require __DIR__.'/../includes/footer.php'; ?>
